const express = require('express');
const app = express();

app.use((req, res, next) => {
    const id = req.params.id;
    const name = req.query.name;

    if (isNaN(id)) {
        res.status(400).send('Error: Invalid 'id'');
    } else {
        next();
    }
});

app.listen(3000, () => {
    console.log('Server listening on port 3000');
});

